import{_ as a,C as o,o as d,c as i,a2 as r,E as s}from"./chunks/framework.C90q7Ucc.js";const p=JSON.parse('{"title":"CodeLark 产品文档","description":"","frontmatter":{},"headers":[],"relativePath":"product/index.md","filePath":"product/index.md","lastUpdated":1781278400000}'),l={name:"product/index.md"};function n(c,e,h,u,b,m){const t=o("MermaidDiagram");return d(),i("div",null,[e[0]||(e[0]=r('<h1 id="codelark-产品文档" tabindex="-1">CodeLark 产品文档 <a class="header-anchor" href="#codelark-产品文档" aria-label="Permalink to &quot;CodeLark 产品文档&quot;">​</a></h1><p>这是 CodeLark 的产品功能文档入口。文档按网页目录组织：每页聚焦一个主题，既面向用户理解功能，也为开发者提供源码入口。</p><p>如果只想安装和启动，先看 <a href="./../guide/install-and-usage">安装与使用指南</a>。如果要理解底层身份链路，再看 <a href="./../architecture/current">当前架构</a>。</p><h2 id="阅读路径" tabindex="-1">阅读路径 <a class="header-anchor" href="#阅读路径" aria-label="Permalink to &quot;阅读路径&quot;">​</a></h2><ol><li><a href="./commands">命令体系</a>：IM 命令如何按用户任务分组。</li><li><a href="./runtime-providers">运行时与提供方</a>：Codex / Claude Code 与 sdk / pty / tmux 的能力边界。</li><li><a href="./channels-ui">通道与 Web 工作台</a>：飞书、多实例配置和本地 UI。</li><li><a href="./data-observability">数据、可观测性与验证</a>：本地文件、日志、状态、真实飞书 E2E。</li><li><a href="./developer-map">开发者源码地图</a>：按功能查源码和测试。</li></ol><h2 id="产品主线" tabindex="-1">产品主线 <a class="header-anchor" href="#产品主线" aria-label="Permalink to &quot;产品主线&quot;">​</a></h2><p>CodeLark 是一个运行在本机的桥接应用，把本机 Codex 和 Claude Code 会话接入飞书 IM 通道，让用户可以在聊天软件里继续本地 AI coding session、切换线程、查看状态、处理权限、接收流式卡片、回传文件，并用 Web 工作台管理通道和会话。</p><p>核心链路是：</p>',8)),s(t,{code64:""}),e[1]||(e[1]=r('<p>CodeLark 自己拥有的是 <code>BridgeSession</code>、<code>ChannelChat</code>、通道配置、消息缓存和审计日志；Codex / Claude Code 自己的会话文件仍由对应工具生成和维护。</p><h2 id="代码入口" tabindex="-1">代码入口 <a class="header-anchor" href="#代码入口" aria-label="Permalink to &quot;代码入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>入口</th></tr></thead><tbody><tr><td>CLI 和本地服务</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/entrypoints/cli.ts" target="_blank" rel="noreferrer">src/entrypoints/cli.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/local-service/manager.ts" target="_blank" rel="noreferrer">src/local-service/manager.ts</a></td></tr><tr><td>Bridge 主循环</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/entrypoints/daemon.ts" target="_blank" rel="noreferrer">src/entrypoints/daemon.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/host/manager.ts" target="_blank" rel="noreferrer">src/bridge/host/manager.ts</a></td></tr><tr><td>Web 工作台</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/operator-ui/server.ts" target="_blank" rel="noreferrer">src/operator-ui/server.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/operator-ui/shell.ts" target="_blank" rel="noreferrer">src/operator-ui/shell.ts</a></td></tr><tr><td>IM 通道抽象</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/channels/contracts.ts" target="_blank" rel="noreferrer">src/channels/contracts.ts</a></td></tr><tr><td>命令分发</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/dispatch.ts" target="_blank" rel="noreferrer">src/bridge/command/dispatch.ts</a></td></tr><tr><td>运行时提供方路由</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/codex/routing-provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/routing-provider.ts</a></td></tr><tr><td>本地 JSON 存储</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a></td></tr><tr><td>配置 schema</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/schemas/config.v1.schema.json" target="_blank" rel="noreferrer">schemas/config.v1.schema.json</a></td></tr></tbody></table><h2 id="维护原则" tabindex="-1">维护原则 <a class="header-anchor" href="#维护原则" aria-label="Permalink to &quot;维护原则&quot;">​</a></h2><ul><li>功能说明先写“用户能做什么、为什么需要、什么时候用”，再写设计模块和源码入口。</li><li>不把实现细节写成产品承诺。</li><li>不把废弃字段当成运行时概念，例如旧 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_origin</code>。</li><li>涉及真实飞书行为时，同步检查 <a href="./../testing/real-feishu/">真实飞书 E2E</a> 和 <a href="./../testing/coverage-audit">覆盖审计</a>。</li></ul>',5))])}const _=a(l,[["render",n]]);export{p as __pageData,_ as default};
